import type {
  GeneratedFile,
  GeneratorOptions,
  PlatformGenerator,
} from "@dota-themes/generator-core";
import { darken } from "@dota-themes/generator-core";
import type { HeroPalette } from "@dota-themes/palettes";

function generateLua(palette: HeroPalette): string {
  const e = palette.editor;
  const c = palette.colors;
  const name = palette.metadata.title;
  const heroSlug = palette.hero;

  const lines: string[] = [
    `-- ${name} theme for Neovim`,
    "-- Generated by dota-themes",
    `-- ${palette.metadata.description}`,
    "",
    `local theme_name = "dota-${heroSlug}"`,
    "",
    "local theme = {",
    "  colors = {",
    `    base = "${e.background}",`,
    `    mantle = "${darken(e.background, 0.05)}",`,
    `    surface0 = "${darken(e.background, -0.03)}",`,
    `    surface1 = "${darken(e.background, -0.06)}",`,
    `    surface2 = "${darken(e.background, -0.09)}",`,
    `    overlay0 = "${e.comment}",`,
    `    overlay1 = "${e.gutter}",`,
    `    overlay2 = "${e.whitespace}",`,
    `    text = "${e.foreground}",`,
    `    subtext0 = "${darken(e.foreground, 0.15)}",`,
    `    subtext1 = "${darken(e.foreground, 0.08)}",`,
    `    primary = "${c.primary}",`,
    `    secondary = "${c.secondary}",`,
    `    accent = "${c.accent}",`,
    `    error = "${c.error}",`,
    `    warning = "${c.warning}",`,
    `    info = "${c.info}",`,
    `    success = "${c.success}",`,
    `    cursor = "${e.cursor}",`,
    `    selection = "${e.selection}",`,
    `    lineHighlight = "${e.lineHighlight}",`,
    `    gutter = "${e.gutter}",`,
    "  },",
    "  highlights = {",
    `    Normal = { fg = "${e.foreground}", bg = "${e.background}" },`,
    `    NormalFloat = { fg = "${e.foreground}", bg = "${e.background}" },`,
    `    NormalNC = { fg = "${e.foreground}", bg = "${e.background}" },`,
    "",
    `    Cursor = { fg = "${e.background}", bg = "${e.cursor}" },`,
    `    CursorLine = { bg = "${e.lineHighlight}" },`,
    `    CursorColumn = { bg = "${e.lineHighlight}" },`,
    "",
    `    Visual = { bg = "${e.selection}" },`,
    `    VisualNOS = { bg = "${e.selection}" },`,
    "",
    `    LineNr = { fg = "${e.gutter}" },`,
    `    CursorLineNr = { fg = "${e.cursor}" },`,
    "",
    `    SignColumn = { bg = "${e.background}" },`,
    `    FoldColumn = { bg = "${e.background}" },`,
    `    Folded = { bg = "${e.lineHighlight}" },`,
    "",
    `    Comment = { fg = "${e.comment}", italic = true },`,
    `    Keyword = { fg = "${e.keyword}" },`,
    `    Statement = { fg = "${e.keyword}" },`,
    `    Conditional = { fg = "${e.keyword}" },`,
    `    Repeat = { fg = "${e.keyword}" },`,
    `    Label = { fg = "${e.keyword}" },`,
    "",
    `    String = { fg = "${e.string}" },`,
    `    Character = { fg = "${e.string}" },`,
    "",
    `    Number = { fg = "${e.number}" },`,
    `    Float = { fg = "${e.number}" },`,
    `    Boolean = { fg = "${e.constant}" },`,
    "",
    `    Function = { fg = "${e.function}" },`,
    "",
    `    Identifier = { fg = "${e.variable}" },`,
    "",
    `    Type = { fg = "${e.type}" },`,
    `    Structure = { fg = "${e.type}" },`,
    `    Typedef = { fg = "${e.type}" },`,
    "",
    `    Constant = { fg = "${e.constant}" },`,
    `    Define = { fg = "${e.keyword}" },`,
    `    Macro = { fg = "${e.keyword}" },`,
    `    PreCondit = { fg = "${e.keyword}" },`,
    `    PreProc = { fg = "${e.keyword}" },`,
    `    Include = { fg = "${e.keyword}" },`,
    "",
    `    Operator = { fg = "${e.operator}" },`,
    `    Delimiter = { fg = "${e.punctuation}" },`,
    "",
    `    Tag = { fg = "${e.tag}" },`,
    `    Attribute = { fg = "${e.attribute}" },`,
    "",
    `    Class = { fg = "${e.class}" },`,
    `    Interface = { fg = "${e.interface}" },`,
    `    Enum = { fg = "${e.enum}" },`,
    `    EnumMember = { fg = "${e.enum}" },`,
    "",
    `    Parameter = { fg = "${e.parameter}" },`,
    `    Property = { fg = "${e.property}" },`,
    "",
    `    Builtin = { fg = "${e.builtin}" },`,
    "",
    `    Special = { fg = "${c.accent}" },`,
    `    SpecialChar = { fg = "${c.accent}" },`,
    `    SpecialKey = { fg = "${e.gutter}" },`,
    "",
    `    Error = { fg = "${c.error}" },`,
    `    WarningMsg = { fg = "${c.warning}" },`,
    `    InfoMsg = { fg = "${c.info}" },`,
    `    MoreMsg = { fg = "${c.success}" },`,
    "",
    `    Todo = { fg = "${c.accent}", bold = true },`,
    `    Search = { fg = "${e.background}", bg = "${c.accent}" },`,
    `    IncSearch = { fg = "${e.background}", bg = "${e.cursor}" },`,
    "",
    `    Pmenu = { fg = "${e.foreground}", bg = "${darken(e.background, 0.05)}" },`,
    `    PmenuSel = { fg = "${e.foreground}", bg = "${e.selection}" },`,
    `    PmenuSbar = { bg = "${darken(e.background, 0.08)}" },`,
    `    PmenuThumb = { bg = "${e.comment}" },`,
    "",
    `    StatusLine = { fg = "${e.foreground}", bg = "${darken(e.background, 0.08)}" },`,
    `    StatusLineNC = { fg = "${e.comment}", bg = "${darken(e.background, 0.08)}" },`,
    `    WinSeparator = { fg = "${darken(e.background, -0.08)}" },`,
    "",
    `    TabLine = { bg = "${darken(e.background, 0.05)}" },`,
    `    TabLineFill = { bg = "${darken(e.background, 0.05)}" },`,
    `    TabLineSel = { fg = "${e.foreground}", bg = "${e.background}" },`,
    "",
    `    Title = { fg = "${c.primary}", bold = true },`,
    `    Directory = { fg = "${c.primary}" },`,
    "",
    "    Underlined = { underline = true },",
    "    Bold = { bold = true },",
    "    Italic = { italic = true },",
    "",
    `    HealthError = { fg = "${c.error}" },`,
    `    HealthWarning = { fg = "${c.warning}" },`,
    `    HealthSuccess = { fg = "${c.success}" },`,
    "",
    `    DiagnosticError = { fg = "${c.error}" },`,
    `    DiagnosticWarn = { fg = "${c.warning}" },`,
    `    DiagnosticInfo = { fg = "${c.info}" },`,
    `    DiagnosticHint = { fg = "${c.success}" },`,
    "",
    `    DiffAdd = { bg = "${darken(c.success, 0.3)}" },`,
    `    DiffDelete = { bg = "${darken(c.error, 0.3)}" },`,
    `    DiffChange = { bg = "${darken(c.info, 0.3)}" },`,
    `    DiffText = { bg = "${darken(c.info, 0.2)}" },`,
    "",
    `    GitSignsAdd = { fg = "${c.success}" },`,
    `    GitSignsChange = { fg = "${c.info}" },`,
    `    GitSignsDelete = { fg = "${c.error}" },`,
    "  },",
    "}",
    "",
    "return theme",
  ];

  return lines.join("\n");
}

export const neovimGenerator: PlatformGenerator = {
  name: "neovim",
  fileExtension: "lua",

  generate(options: GeneratorOptions): GeneratedFile[] {
    const content = generateLua(options.hero);
    const fileName = `dota-${options.hero.hero}.lua`;
    return [{ path: `${options.outputDir}/${fileName}`, content }];
  },
};
